  ({params, imports}) => {
    const programEncounter = params.entity;
    const formElement = params.formElement;


    const colors = ['Green', 'Orange', 'Red'];
    let finalColor = 'Green';

    let changeColor = (color) => {
        if (colors.indexOf(color) > colors.indexOf(finalColor)) {
            finalColor = color;
        }
    }
    let temperature = programEncounter.getObservationReadableValue('Fever?');
    const temperatures = programEncounter.programEnrolment.getObservationsForConceptName('Fever?');
    let feverDays = temperatures.filter(temperature => temperature.obs === '04bb1773-c353-44a1-a68c-9b448e07ff70')
    if (temperature === 'Yes' && feverDays.length > 3) {
        changeColor('Red');
    }
    let cough = programEncounter.getObservationReadableValue('Cough?');
    const coughh = programEncounter.programEnrolment.getObservationsForConceptName('Cough?');
    let coughDays = coughh.filter(cough => cough.obs === '04bb1773-c353-44a1-a68c-9b448e07ff70')
    if (cough === 'Yes' && coughDays.length > 3) {
        changeColor('Red');
    }
    let saturation = programEncounter.getObservationReadableValue('Saturation value');
       if  (saturation < 94) { 
            changeColor('Red');
            }
       if  (saturation == 94) { 
            changeColor('Orange');
            }
    let Respiratory = programEncounter.getObservationReadableValue('Respiratory rate value');
       if  (Respiratory > 26) { 
            changeColor('Red');
            }
       if  (Respiratory >= 24 && Respiratory <= 26) { 
            changeColor('Orange');
            }
    return new imports.rulesConfig.FormElementStatus(formElement.uuid, true, finalColor);
}

