'use strict';
({params, imports}) => {
  const programEnrolment = params.entity;
  const formElement = params.formElement;

  const lmpDate = programEnrolment.getObservationValue('Last menstrual period');

  if (lmpDate !== undefined && lmpDate !== null) {
    const value = ruleServiceLibraryInterfaceForSharingModules.motherCalculations.estimatedDateOfDelivery(programEnrolment);
    return new imports.rulesConfig.FormElementStatus(formElement.uuid, true, value);
  } else {
    return new imports.rulesConfig.FormElementStatus(formElement.uuid, false, null);
  }
};

