"use strict";
({params, imports}) => {
   const programEncounter = params.entity;
   const formElement = params.formElement;  
   const format = "DD-MMM-YYYY";
   const chaayaFirstDate = programEncounter.getObservationValue('Date of first administration of chaaya tablet');
    //console.log('antaraFirstDate',antaraFirstDate);

    let value = imports.moment(chaayaFirstDate).add(3, 'days').format(format);
    let visitDateOnThreeMonths = imports.moment(chaayaFirstDate).add(3, 'months').format(format);
    let visitDate = programEncounter.encounterDateTime;

    let visibility = false;

    if(imports.moment(visitDate).isSameOrBefore(visitDateOnThreeMonths))
      visibility = true;

    //console.log('value date', value);
    return new imports.rulesConfig.FormElementStatus(formElement.uuid, visibility,value );
};

"use strict";
({params, imports}) => {
   const programEncounter = params.entity;
   const formElement = params.formElement;  
   const format = "DD-MMM-YYYY";
   const chaayaFirstDate = programEncounter.getObservationValue('Date of first administration of chaaya tablet');
    //console.log('antaraFirstDate',antaraFirstDate);

    let value = imports.moment(chaayaFirstDate).add(7, 'days').format(format);

    let visitDateOnThreeMonths = imports.moment(chaayaFirstDate).add(3, 'months').format(format);
    let visitDate = programEncounter.encounterDateTime;

    let visibility = false;

    if(imports.moment(visitDate).isSameOrAfter(visitDateOnThreeMonths))
      visibility = true;
    //console.log('value date', value);
    return new imports.rulesConfig.FormElementStatus(formElement.uuid, visibility,value );
};

